$ErrorActionPreference='Stop'
[Console]::OutputEncoding=[System.Text.UTF8Encoding]::new()
$Core='C:\ENGREMIAT_CORE'
$DataIntake=Join-Path $Core 'tools\launcher\ENGREMIAT-DATA-INTAKE-CENTER.ps1'
function W([string]$m,[string]$c='Gray'){try{Write-Host $m -ForegroundColor $c}catch{Write-Host $m}}
function P(){Write-Host '';Read-Host '[Enter] volver / refrescar'|Out-Null}
function Header([string]$section=''){Clear-Host;W '==== MEMORIA Y DOCUMENTACION / CENTRO DOCUMENTAL ====' Cyan;W 'Ruta: INICIO > [15] Memoria y documentacion' DarkGray;W 'Rol: consumidor documental de fichas, memoria viva y salidas humanas' Gray;W 'Principio: Data Intake produce fichas; Centro Documental genera documentos' DarkGray;if($section){W $section Yellow};W ''}
function Val($o,[string[]]$names,[string]$fallback='No definido'){foreach($n in $names){if($o.PSObject.Properties.Name -contains $n){$v=$o.$n;if($null -ne $v){$s=if($v -is [array]){($v -join ', ')}else{[string]$v};$s=$s.Trim();if($s -and $s -ne 'No definido' -and $s -ne 'PENDIENTE_DEFINIR'){return $s}}}};return $fallback}
function Arr($o,[string[]]$names,[string[]]$fallback){foreach($n in $names){if($o.PSObject.Properties.Name -contains $n -and $null -ne $o.$n){$a=@($o.$n)|Where-Object{$_ -and ([string]$_).Trim() -and $_ -ne 'No definido' -and $_ -ne 'PENDIENTE_DEFINIR'};if($a.Count){return $a}}};return $fallback}
function ActiveProfilePath(){$p=Join-Path $Core 'documents\grants\grant-call-profile-latest.json';New-Item -ItemType Directory -Force -Path (Split-Path $p -Parent)|Out-Null;return $p}
function EnsureProfile(){$p=ActiveProfilePath;if(!(Test-Path $p)){$o=[ordered]@{nombre_convocatoria='Convocatoria demo de innovacion social y economia circular';entidad_convocante='Entidad publica demo';territorio='Catalunya / España';fecha_limite='2026-12-31';objetivo_convocatoria='Financiar proyectos piloto con impacto social, economia circular y digitalizacion local.';lineas_prioritarias=@('Economia circular','Innovacion social','Digitalizacion local');importe_solicitado='50000 EUR';cofinanciacion='No requerida / pendiente de bases especificas';beneficiarios='Comunidades locales, entidades sociales y administraciones colaboradoras.';indicadores_requeridos=@('Personas beneficiarias','Tareas completadas','Evidencias documentadas');documentacion_requerida=@('Memoria tecnica','Presupuesto','Cronograma','Indicadores');criterios_valoracion=@('Innovacion social','Impacto medible','Viabilidad tecnica');tono='tecnico, claro, institucional y orientado a impacto';status='ready';human_review_required=$false;pending_fields=@()};$o|ConvertTo-Json -Depth 50|Set-Content $p -Encoding UTF8};return $p}
function EditGrantProfile(){$p=EnsureProfile;Start-Process notepad.exe $p;Header 'FICHA DE CONVOCATORIA';W 'OK ficha_abierta=True' Green;W $p Cyan;P}
function AssistGrantProfile(){$p=EnsureProfile;$j=Get-Content $p -Raw|ConvertFrom-Json;Header 'ASISTENTE MINIMO DE FICHA';W 'Deja vacío para mantener valor actual.' DarkGray;$fields=@('nombre_convocatoria','entidad_convocante','territorio','fecha_limite','importe_solicitado','cofinanciacion','beneficiarios','tono');foreach($f in $fields){$cur=if($j.PSObject.Properties.Name -contains $f){[string]$j.$f}else{''};$v=Read-Host ($f+' ['+$cur+']');if($v.Trim()){if($j.PSObject.Properties.Name -contains $f){$j.$f=$v}else{$j|Add-Member -NotePropertyName $f -NotePropertyValue $v}}};$j.status='ready';$j.human_review_required=$false;$j.pending_fields=@();$j|ConvertTo-Json -Depth 60|Set-Content $p -Encoding UTF8;Header 'FICHA ACTUALIZADA';W 'OK ficha_actualizada=True' Green;W $p Cyan;P}
function GenerateAdaptedDossier(){$p=EnsureProfile;$j=Get-Content $p -Raw|ConvertFrom-Json;$dir=Join-Path $Core 'documents\grants';$stamp=Get-Date -Format 'yyyyMMdd-HHmmss';$latest=Join-Path $dir 'dossier-subvenciones-adaptado-latest.md';$version=Join-Path $dir ('dossier-subvenciones-adaptado-'+$stamp+'.md');$reportDir=Join-Path $Core 'reports\launcher';New-Item -ItemType Directory -Force -Path $dir,$reportDir|Out-Null;$nombre=Val $j @('nombre_convocatoria','convocatoria_nombre','titulo');$entidad=Val $j @('entidad_convocante','entity');$territorio=Val $j @('territorio','territory');$fecha=Val $j @('fecha_limite','deadline');$objetivo=Val $j @('objetivo_convocatoria','summary','resumen');$importe=Val $j @('importe_solicitado','importe_maximo','amount');$cofin=Val $j @('cofinanciacion');$benef=Val $j @('beneficiarios');$tono=Val $j @('tono') 'tecnico, claro, institucional y orientado a impacto';$lineas=Arr $j @('lineas_prioritarias') @('Economia circular','Innovacion social');$indicadores=Arr $j @('indicadores_requeridos') @('Personas beneficiarias','Evidencias documentadas');$docs=Arr $j @('documentacion_requerida','required_documents') @('Memoria tecnica','Presupuesto');$criterios=Arr $j @('criterios_valoracion','criterios','criteria') @('Impacto medible','Viabilidad tecnica');$miss=@();foreach($kv in @(@('nombre_convocatoria',$nombre),@('entidad_convocante',$entidad),@('territorio',$territorio),@('fecha_limite',$fecha),@('objetivo_convocatoria',$objetivo),@('importe_solicitado',$importe),@('cofinanciacion',$cofin),@('beneficiarios',$benef),@('tono',$tono))){if($kv[1] -eq 'No definido'){$miss+=$kv[0]}};if($miss.Count){Header 'WARN FICHA INCOMPLETA';$miss|ForEach-Object{W ('[MISS] '+$_) Yellow};$go=Read-Host 'GENERAR_CON_FICHA_INCOMPLETA s/n';if($go -ne 's'){return}};$lines=@('# Dossier adaptado a convocatoria','','## Convocatoria',$nombre,'','## Entidad convocante',$entidad,'','## Territorio',$territorio,'','## Fecha limite',$fecha,'','## Objetivo de la convocatoria',$objetivo,'','## Lineas prioritarias',($lineas|ForEach-Object{'- '+$_}),'','## Importe solicitado',$importe,'','## Cofinanciacion',$cofin,'','## Beneficiarios',$benef,'','## Indicadores requeridos',($indicadores|ForEach-Object{'- '+$_}),'','## Documentacion requerida',($docs|ForEach-Object{'- '+$_}),'','## Criterios de valoracion',($criterios|ForEach-Object{'- '+$_}),'','## Tono',$tono,'','## Encaje Engremiat','Engremiat se presenta como infraestructura local-first para convertir entradas de datos en fichas, documentos, tareas, modulos y evidencias con supervision humana.');$lines|Set-Content $latest -Encoding UTF8;Copy-Item $latest $version -Force;$rep=Join-Path $reportDir ('grant-adapted-dossier-normalized-'+$stamp+'.json');[pscustomobject]@{status='PASS';dossier=$latest;version=$version;source_profile=$p;missing=$miss}|ConvertTo-Json -Depth 40|Set-Content $rep -Encoding UTF8;Header 'DOSSIER ADAPTADO GENERADO';W ('[OK] dossier: '+$latest) Green;W ('[OK] version: '+$version) Green;W ('[OK] report:  '+$rep) Green;P}
function OpenDataIntake(){if(Test-Path $DataIntake){& powershell -NoProfile -ExecutionPolicy Bypass -File $DataIntake}else{Header 'DATA INTAKE NO ENCONTRADO';W $DataIntake Red;P}}
function SubConvocatorias(){while($true){Header 'CONVOCATORIAS Y FICHAS';W '[14] crear/editar ficha de convocatoria';W '[15] generar dossier adaptado a convocatoria';W '[16] asistente rellenar ficha convocatoria';W '[17] Data Intake / Entrada de datos y fichas';W '';W '[b] volver | [Enter] refrescar | ? = ayuda' DarkGray;W '';$op=Read-Host 'CONVOCATORIAS';switch($op){'14'{EditGrantProfile};'15'{GenerateAdaptedDossier};'16'{AssistGrantProfile};'17'{OpenDataIntake};'b'{return};''{continue};'?'{Header 'AYUDA CONVOCATORIAS';W '[14] abre JSON activo. [15] genera dossier. [16] asistente minimo. [17] Data Intake.';P};default{W 'Opcion no reconocida' Yellow;Start-Sleep -Milliseconds 700}}}}
function ShowSub([string]$title,[string[]]$items){while($true){Header $title;foreach($i in $items){W $i};W '';W '[b] volver | [Enter] refrescar' DarkGray;W '';$op=Read-Host 'DOCUMENTACION_SUBMENU';switch($op){'b'{return};''{continue};default{W 'Handler directo pendiente. Usa submenu Convocatorias ya cableado o legacy actual.' Yellow;Start-Sleep -Milliseconds 900}}}}
function Menu(){while($true){Header;W '[1] Memoria viva';W '[2] Dossiers';W '[3] Convocatorias y fichas';W '[4] Contexto worker / continuidad';W '[5] Exportaciones y herramientas';W '[6] Carpetas y archivos';W '[7] Estado y ayuda';W '';W '[b] volver | [Enter] refrescar | ? = ayuda' DarkGray;W '';$op=Read-Host 'DOCUMENTACION';switch($op){'1'{ShowSub 'MEMORIA VIVA' @('[2] abrir memoria tecnica','[3] abrir resumen humano','[4] abrir informe de desarrollo')};'2'{ShowSub 'DOSSIERS' @('[5] abrir dossier subvenciones','[6] abrir dossier partners','[7] abrir dossier clientes','[15] generar dossier adaptado a convocatoria')};'3'{SubConvocatorias};'4'{ShowSub 'CONTEXTO WORKER / CONTINUIDAD' @('[8] abrir contexto worker','[10] abrir contexto JSON')};'5'{ShowSub 'EXPORTACIONES Y HERRAMIENTAS' @('[11] exportar documentos DOCX/HTML con Pandoc','[12] abrir carpeta exports','[13] verificar herramientas documentales')};'6'{ShowSub 'CARPETAS Y ARCHIVOS' @('[9] abrir carpeta documents')};'7'{Header 'ESTADO Y AYUDA';W 'Submenu Convocatorias y fichas cableado con handlers reales.' Green;P};'b'{return};''{continue};'?'{Header 'AYUDA';W 'Pantalla normalizada. El submenu [3] ya esta cableado.';P};default{W 'Opcion no reconocida' Yellow;Start-Sleep -Milliseconds 700}}}}
Menu
